# Concrete shape implementations

from types_data import Color, ShapeType, Point, PI_APPROX
from geometry_base import Shape, IDrawable, IMeasurable

class Rectangle(Shape):
    width: float
    height: float
    top_left: Point

    def __init__(self, width: float, height: float, top_left: Point, color: Color):
        super().__init__(color, ShapeType.RECTANGLE)
        self.width = width
        self.height = height
        self.top_left = top_left

    @override
    def describe(self) -> str:
        w: str = str(self.width)
        h: str = str(self.height)
        return "Rectangle " + w + "x" + h

    @override
    def draw(self) -> str:
        p: str = str(self.top_left)
        return "Drawing rectangle at " + p

    @override
    def get_area(self) -> float:
        return self.width * self.height

    @override
    def get_perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

class Circle(Shape):
    radius: float
    center: Point

    def __init__(self, radius: float, center: Point, color: Color):
        super().__init__(color, ShapeType.CIRCLE)
        self.radius = radius
        self.center = center

    @override
    def describe(self) -> str:
        r: str = str(self.radius)
        return "Circle radius " + r

    @override
    def draw(self) -> str:
        c: str = str(self.center)
        return "Drawing circle at " + c

    @override
    def get_area(self) -> float:
        r2: float = self.radius * self.radius
        return PI_APPROX * r2

    @override
    def get_perimeter(self) -> float:
        return 2.0 * PI_APPROX * self.radius
